import { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import API from '../api/axios';

const ProfilePage = () => {
  const { user, setUser } = useAuth();

  const [name, setName] = useState(user?.name || '');
  const [username, setUsername] = useState(user?.username || '');
  const [bio, setBio] = useState(user?.bio || '');
  const [pic, setPic] = useState(null);
  const [curPw, setCurPw] = useState('');
  const [newPw, setNewPw] = useState('');
  const [msg, setMsg] = useState('');
  const [darkMode, setDarkMode] = useState(false);

  useEffect(() => {
    const saved = localStorage.getItem("user-theme");
    setDarkMode(saved === "dark");
  }, []);

  useEffect(() => {
    const handleThemeChange = () => {
      const saved = localStorage.getItem("user-theme");
      setDarkMode(saved === "dark");
    };

    window.addEventListener("storage", handleThemeChange);
    return () => window.removeEventListener("storage", handleThemeChange);
  }, []);

  useEffect(() => {
    if (!msg) return;
    const timer = setTimeout(() => setMsg(''), 3000);
    return () => clearTimeout(timer);
  }, [msg]);

  const handleProfile = async (e) => {
    e.preventDefault();
    setMsg('');

    const fd = new FormData();
    fd.append('name', name);
    fd.append('bio', bio);
    fd.append('username', username);
    if (pic) fd.append('profilePic', pic);

    try {
      const { data } = await API.put('/auth/profile', fd);
      setUser(data);
      setMsg('Profile updated successfully!');
    } catch (err) {
      setMsg(err.response?.data?.message || 'Error updating profile');
    }
  };

  const handlePassword = async (e) => {
    e.preventDefault();
    setMsg('');

    try {
      await API.put('/auth/change-password', {
        currentPassword: curPw,
        newPassword: newPw,
      });

      setMsg('Password changed successfully!');
      setCurPw('');
      setNewPw('');
    } catch (err) {
      setMsg(err.response?.data?.message || 'Error changing password');
    }
  };

  const picSrc = user?.profilePic
    ? `http://localhost:5000/uploads/${user.profilePic}`
    : '/default-avatar.png';

  const styles = {
    page: {
      background: darkMode ? "#560032" : "#FAE8ED",
      minHeight: '100vh',
      padding: '40px 20px',
      display: 'flex',
      justifyContent: 'center',
      alignItems: 'center',
      color: darkMode ? "#f5c2da" : "#f4b5e5",
    },
    container: {
      width: '100%',
      maxWidth: '650px',
      backgroundColor: darkMode ? "#2e091e" : "#f7c6d9",
      padding: '35px',
      borderRadius: '25px',
      boxShadow: darkMode
        ? "0 0 25px rgba(0,0,0,0.6)"
        : "0 12px 35px rgba(0,0,0,0.12)",
    },
    heading: {
      fontSize: '34px',
      marginBottom: '20px',
      fontWeight: 'bold',
      textAlign: 'center',
      color: darkMode ? "#f7c6d9" : "#0c4b34",
    },
    profilePic: {
      width: '150px',
      height: '150px',
      borderRadius: '50%',
      objectFit: 'cover',
      margin: '0 auto 20px',
      display: 'block',
      border: darkMode ? '4px solid #7f0859' : '5px solid #fff',
      boxShadow: '0 6px 18px rgba(0,0,0,0.15)',
    },
    message: {
      marginBottom: '15px',
      fontWeight: 'bold',
      textAlign: 'center',
      color: '#19a350',
    },
    form: {
      display: 'flex',
      flexDirection: 'column',
      gap: '16px',
      marginTop: '20px',
      marginBottom: '30px',
    },
    subHeading: {
      fontSize: '20px',
      fontWeight: 'bold',
      textAlign: 'center',
      marginBottom: '10px',
      color: darkMode ? "#f7bbd5" : "#0c4b34",
    },
    input: {
      width: '100%',
      padding: '14px 18px',
      borderRadius: '50px',
      border: darkMode ? "1px solid #5c1f4b" : "1px solid transparent",
      outline: 'none',
      backgroundColor: darkMode ? "#381727" : "#fff",
      color: darkMode ? "#ecfdf5" : "#000",
      fontSize: '15px',
    },
    textarea: {
      width: '100%',
      padding: '14px 18px',
      borderRadius: '15px',
      border: darkMode ? "1px solid #5c1f4b" : "1px solid transparent",
      outline: 'none',
      backgroundColor: darkMode ? "#381727" : "#fff",
      color: darkMode ? "#ecfdf5" : "#000",
      fontSize: '15px',
      resize: 'none',
    },
    fileWrapper: {
      display: "flex",
      alignItems: "center",
      justifyContent: "space-between",
      gap: "10px",
      padding: "12px",
      borderRadius: "12px",
      background: darkMode ? "#381727" : "#fff",
      border: darkMode ? "1px solid #5c1f4b" : "1px solid #ddd",
    },
    fileInput: { display: "none" },
    fileLabel: {
      padding: "10px 16px",
      borderRadius: "20px",
      background: darkMode ? "#f3a7c4" : "rgb(12,75,52)",
      color: darkMode ? "#381727" : "#fff",
      cursor: "pointer",
      fontWeight: "bold",
      fontSize: "14px",
    },
    fileName: {
      fontSize: "13px",
      flex: 1,
      textAlign: "right",
      opacity: 0.8,
      color: darkMode ? "#f3a7b6" : "#333",
    },
    button: {
      width: '100%',
      padding: '14px',
      borderRadius: '50px',
      border: 'none',
      fontWeight: 'bold',
      cursor: 'pointer',
      backgroundColor: darkMode ? "#c46392" : "rgb(12, 75, 52)",
      color: darkMode ? "#fcfcfc" : "#fff",
      marginTop: '5px'
    },
    label: {
      fontWeight: "bold",
      fontSize: "14px",
      marginBottom: "6px",
      display: "block"
    },
    section: {
      marginBottom: "25px"
    }
  };

  return (
    <div style={styles.page}>
      <div style={styles.container}>
        <h2 style={styles.heading}>My Profile</h2>

        <img src={picSrc} alt="Profile" style={styles.profilePic} />

        {msg && <p style={styles.message}>{msg}</p>}

        {/* EDIT PROFILE */}
        <form style={styles.form} onSubmit={handleProfile}>
          <h3 style={styles.subHeading}>Edit Profile</h3>

          <div>
            <label style={styles.label}>Full Name</label>
            <input value={name} onChange={(e) => setName(e.target.value)} style={styles.input}/>
          </div>

          <div>
            <label style={styles.label}>Username</label>
            <input value={username} onChange={(e) => setUsername(e.target.value)} style={styles.input}/>
          </div>

          <div>
            <label style={styles.label}>Bio</label>
            <textarea value={bio} onChange={(e) => setBio(e.target.value)} rows={3} style={styles.textarea}/>
          </div>

          <div style={styles.fileWrapper}>
            <label htmlFor="fileUpload" style={styles.fileLabel}>Choose File</label>
            <span style={styles.fileName}>{pic ? pic.name : "No file chosen"}</span>
            <input id="fileUpload" type="file" onChange={(e) => setPic(e.target.files[0])} style={styles.fileInput}/>
          </div>

          <button type="submit" style={styles.button}>Save Profile</button>
        </form>

        {/* EMAIL */}
        <div style={styles.section}>
          <label style={styles.label}>Email</label>
          <input value={user?.email || ""} disabled style={{ ...styles.input, opacity: 0.7 }}/>
        </div>

        {/* PASSWORD */}
        <form style={styles.form} onSubmit={handlePassword}>
          <h3 style={styles.subHeading}>Change Password</h3>

          <input type="password" placeholder="Current password" value={curPw} onChange={(e) => setCurPw(e.target.value)} style={styles.input}/>
          <input type="password" placeholder="New password" value={newPw} onChange={(e) => setNewPw(e.target.value)} style={styles.input}/>

          <button type="submit" style={styles.button}>Change Password</button>
        </form>
      </div>
    </div>
  );
};

export default ProfilePage;
